insert into public.chapters (id, scene_id, "order", label, scroll_anchor_y, narration) values
  ('ch-children', 'scene-main-street', 4, 'Children of Gaza City',                  0.18, 'By October 2025, UNICEF reported that an estimated 64,000 children had been killed or maimed across Gaza, including more than 1,000 babies, in two years of war. Save the Children''s clinics counted a tenfold rise in acute malnutrition during the months of total siege.'),
  ('ch-medical',  'scene-main-street', 5, 'Medical staff and patients',             0.42, 'On 5 April 2024, a WHO mission to al-Shifa found the once largest referral hospital in Gaza an "empty shell." By December 2024, the UN Human Rights Office documented at least 136 strikes on 27 hospitals across Gaza, with most facilities pushed to the brink of collapse.'),
  ('ch-press',    'scene-main-street', 6, 'Journalists in Gaza City',               0.62, 'On the night of 10 August 2025, an Israeli strike on a press tent at the main gate of al-Shifa Hospital killed Al Jazeera correspondent Anas al-Sharif and four colleagues — part of a CPJ-documented toll of more than 200 journalists killed in Gaza since October 2023.'),
  ('ch-water',    'scene-main-street', 7, 'Water, food, and survival',              0.74, 'On 22 August 2025, the IPC declared famine for the first time in Gaza Governorate, the area that includes Gaza City. Oxfam reported in 2024 that water available to Gazans had fallen by 94 percent — to less than a single toilet flush per person per day.'),
  ('ch-rebuild',  'scene-main-street', 8, 'What rebuilding looks like',             0.90, 'After the October 2025 ceasefire, the Norwegian Refugee Council reported that aid agencies had been able to bring in tents for only a fraction of the 1.29 million Gazans needing shelter. UNRWA had documented some 282,904 housing units damaged or destroyed across the strip.');
