insert into public.timeline_events (id, scene_anchor_id, date, title, summary, event_type, weight, is_published) values
  ('evt-2023-10-07', 'scene-main-street', '2023-10-07', 'Beginning of the 2023-2025 war',                      'Hamas-led attacks on southern Israel are followed by an Israeli air and ground campaign in the Gaza Strip, the start of the war that would reshape Gaza City, including the area around al-Shifa Hospital on Izz al-Din al-Qassam Street.', 'destruction', 0.95, true),
  ('evt-2023-10-11', 'scene-main-street', '2023-10-11', 'ICRC warns hospitals are at breaking point',          'The International Committee of the Red Cross''s Gaza sub-delegation head, William Schomburg, says: "The destruction affecting hospitals in Gaza is becoming unbearable and needs to stop." The ICRC names al-Shifa, Nasser, al-Rantisi and al-Quds among facilities at acute risk.', 'report', 0.7, true),
  ('evt-2023-11-11', 'scene-main-street', '2023-11-11', 'First al-Shifa siege begins',                         'Heavy fighting reaches the al-Shifa Medical Complex in Gaza City. MSF surgeon Dr. Mohammed Obeid sends a voice note from inside the hospital: "We are alone now. No one hears us." The first siege runs through 24 November 2023.', 'destruction', 0.9, true),
  ('evt-2023-11-26', 'scene-main-street', '2023-11-26', 'Rashad al-Shawa Cultural Center destruction reported','During a humanitarian pause, the destruction of Gaza City''s 1985 Rashad al-Shawa Cultural Center, a major civic and cultural landmark in the Rimal district, is documented by reporters and aid workers.', 'destruction', 0.6, true),
  ('evt-2024-01-29', 'scene-main-street', '2024-01-29', 'Killing of Hind Rajab',                               'Six-year-old Hind Rajab and members of her family are killed when their car is shelled while fleeing Gaza City. Two Palestine Red Crescent paramedics, Yousef Zeino and Ahmad al-Madhoun, are killed when their ambulance is hit en route. The case becomes a recurring reference in international reporting on Gaza City.', 'news', 0.85, true),
  ('evt-2024-03-18', 'scene-main-street', '2024-03-18', 'Second al-Shifa siege begins',                        'A second Israeli military operation at and around al-Shifa Hospital begins. MSF staff sheltering nearby report drones, tanks and shelling, and witness fire rising from the main building. The operation runs until 1 April 2024.', 'destruction', 0.9, true),
  ('evt-2024-04-05', 'scene-main-street', '2024-04-05', 'WHO assessment finds al-Shifa an "empty shell"',      'A WHO-led mission to al-Shifa Medical Complex describes the hospital as "an empty shell," with the emergency department, surgical and maternity ward buildings "extensively damaged due to explosives and fire." At least 115 burned beds and 14 destroyed incubators are counted.', 'report', 0.85, true),
  ('evt-2024-04-16', 'scene-main-street', '2024-04-16', 'UN Women: 6,000 mothers killed, 19,000 children orphaned', 'UN Women''s Gender Alert reports that, six months into the war, more than 10,000 women have been killed in Gaza, including an estimated 6,000 mothers, leaving roughly 19,000 children orphaned. Regional Director Susanne Mikhail calls it a "war on women."', 'report', 0.8, true),
  ('evt-2024-07-10', 'scene-main-street', '2024-07-10', 'UNRWA: two-thirds of Gaza schools hit',               'UN News, citing UNRWA Commissioner-General Philippe Lazzarini, reports that "two thirds of UNRWA schools in Gaza have been hit, some were bombed out, many severely damaged," with at peak around one million displaced people sheltering in UNRWA schools.', 'report', 0.75, true),
  ('evt-2024-07-17', 'scene-main-street', '2024-07-17', 'Oxfam: water supply down 94 percent',                  'Oxfam''s Water War Crimes report finds that water available to people in Gaza has fallen by 94 percent, to roughly 4.74 liters per person per day, well under the WHO emergency minimum. Five water and sanitation sites have been damaged or destroyed every three days.', 'report', 0.75, true),
  ('evt-2024-12-05', 'scene-main-street', '2024-12-05', 'Amnesty: genocide finding',                            'Amnesty International publishes a 296-page report concluding that Israel is committing genocide against Palestinians in Gaza. The report draws on satellite imagery and 212 interviews with survivors, displaced people, and field experts.', 'report', 0.85, true),
  ('evt-2024-12-31', 'scene-main-street', '2024-12-31', 'OHCHR: 136 strikes on hospitals',                      'The UN Human Rights Office publishes a thematic report finding at least 136 strikes on at least 27 hospitals and 12 other medical facilities between 7 October 2023 and 30 June 2024, pushing Gaza''s healthcare system to the brink of total collapse.', 'report', 0.85, true),
  ('evt-2025-01-19', 'scene-main-street', '2025-01-19', 'January 2025 ceasefire takes effect',                  'OCHA reports that a ceasefire between Israel and Palestinian armed groups, mediated by Egypt, Qatar, and the United States, takes effect at 11:15 on 19 January 2025. Within days, more than 376,000 displaced people walk north toward their homes.', 'aid', 0.9, true),
  ('evt-2025-08-07', 'scene-main-street', '2025-08-07', 'HRW: 97 percent of Gaza schools damaged',              'Human Rights Watch reports that, by August 2025, 97 percent of Gaza''s school buildings (547 of 564) had sustained damage and 76 percent had been directly hit since October 2023. HRW investigates a 21 September 2024 strike on al-Zeitoun C School.', 'report', 0.8, true),
  ('evt-2025-08-10', 'scene-main-street', '2025-08-10', 'Anas al-Sharif and four colleagues killed at al-Shifa gate', 'An Israeli strike hits a press tent at the main gate of al-Shifa Hospital in Gaza City, killing Al Jazeera correspondent Anas al-Sharif (28), correspondent Mohammed Qreiqeh, and cameramen Ibrahim Zaher, Mohammed Noufal, and Moamen Aliwa. CPJ, the UN, and press groups condemn the attack.', 'destruction', 0.9, true),
  ('evt-2025-08-22', 'scene-main-street', '2025-08-22', 'IPC declares famine in Gaza Governorate',              'The IPC, the UN-backed hunger watchdog, confirms famine in Gaza Governorate — the area that includes Gaza City — for the first time. WHO Director-General Dr. Tedros Adhanom Ghebreyesus calls a ceasefire "an absolute and moral imperative now." UN Secretary-General António Guterres calls it "a failure of humanity itself."', 'report', 0.95, true),
  ('evt-2025-09-09', 'scene-main-street', '2025-09-09', 'Gaza City evacuation order to Al Mawasi',              'The Israeli military orders all residents of Gaza City — from the Old City and at-Tuffah in the east to the sea in the west — to evacuate immediately via the al-Rashid coastal road to Al Mawasi. OCHA records roughly 125,600 displacement movements in the following week.', 'displacement', 0.9, true),
  ('evt-2025-10-30', 'scene-main-street', '2025-10-30', 'NRC: shelter aid still blocked three weeks into ceasefire', 'Three weeks into the October 2025 ceasefire, the Norwegian Refugee Council reports that 23 requests from nine aid agencies for shelter supplies have been rejected. Around 260,000 Palestinian families — roughly 1.5 million people — remain exposed to the winter without adequate cover.', 'report', 0.8, true),
  ('evt-2025-12-19', 'scene-main-street', '2025-12-19', 'IPC: famine no longer occurring',                      'An updated IPC analysis, following the October ceasefire and improved humanitarian and commercial access, finds that no part of Gaza is currently classified in famine, although roughly 1.6 million people (77 percent of the population) still face high levels of acute food insecurity and over 100,000 remain in IPC Phase 5.', 'report', 0.85, true);
